import React, { useState, useContext } from "react";
import {
  AppBar,
  Toolbar,
  IconButton,
  Typography,
  Button,
  Drawer,
  List,
  ListItem,
  ListItemText,
  useMediaQuery,
  Box,
  Menu,
  MenuItem,
} from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import GitHubIcon from "@mui/icons-material/GitHub";
import Brightness4Icon from "@mui/icons-material/Brightness4";
import DarkModeIcon from "@mui/icons-material/DarkModeRounded";
import LightModeIcon from "@mui/icons-material/LightModeRounded";
import { ThemeContext } from "../../utils/switchTheme";
import Projects from "../projects/Projects";
import About from "../../about/About";
import Intro from "../intro/Intro";
import Skills from "../skills/Skills";
import Experience from "../exprience/Exprience";
import Contact from "../contacts/Contacts";




const sections = [
  { title: "About", url: "#about" },
  { title: "Skills", url: "#skills" },
  { title: "Experience", url: "#experience" },
  { title: "Projects", url: "#projects" },
  { title: "Education", url: "#education" },
  { title: "Contact", url: "#contact" },
];

const Dashboard = () => {
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [anchorEl, setAnchorEl] = useState(null);
  const { theme, setTheme } = useContext(ThemeContext);
  const muitheme = useTheme();


  const toggleTheme = (newTheme) => {
    setTheme(newTheme);
  };

  const isMobile = window.innerWidth < 786; 

  return (
    <div style={{ margin: "0 auto", position: "relative", overflow: "hidden" }}>
      <AppBar
        position="fixed"
        sx={{
          width: "100%",
          zIndex: 1201,
          padding: "20px 0",
          borderBottom: "1px solid var(--border)",
          background: "transparent",
        }}
      >
        <Toolbar sx={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          {isMobile && (
            <IconButton edge="start" color="inherit" onClick={() => setDrawerOpen(!drawerOpen)}>
              <MenuIcon />
            </IconButton>
          )}
          <Typography variant="h6">My Portfolio</Typography>
          {!isMobile && (
            <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
              {sections.map((section) => (
                <Button key={section.title} color="inherit" href={section.url}>
                  {section.title}
                </Button>
              ))}
              <IconButton color="inherit" onClick={(e) => setAnchorEl(e.currentTarget)}>
                {theme === "dark" ? (
                  <DarkModeIcon />
                ) : theme === "light" ? (
                  <LightModeIcon />
                ) : (
                  <Brightness4Icon />
                )}
              </IconButton>
              <Menu anchorEl={anchorEl} open={Boolean(anchorEl)} onClose={() => setAnchorEl(null)}>
                <MenuItem onClick={() => toggleTheme("light")}>
                  <LightModeIcon sx={{ marginRight: 1 }} /> Light
                </MenuItem>
                <MenuItem onClick={() => toggleTheme("dark")}>
                  <DarkModeIcon sx={{ marginRight: 1 }} /> Dark
                </MenuItem>
                <MenuItem onClick={() => toggleTheme("system")}>
                  <Brightness4Icon sx={{ marginRight: 1 }} /> System
                </MenuItem>
              </Menu>
              <IconButton color="inherit" href="https://github.com" target="_blank">
                <GitHubIcon />
              </IconButton>
            </Box>
          )}
        </Toolbar>
      </AppBar>
      <Drawer anchor="left" open={drawerOpen} onClose={() => setDrawerOpen(false)}>
        <Box sx={{ width: 250, padding: 2 }}>
          <Typography variant="h6" sx={{ marginBottom: 2 }}>
            My Portfolio
          </Typography>
          <List>
            {sections.map((section) => (
              <ListItem button key={section.title} onClick={() => setDrawerOpen(false)} component="a" href={section.url}>
                <ListItemText primary={section.title} />
              </ListItem>
            ))}
          </List>
        </Box>
      </Drawer>
      <Box sx={{ marginTop: "84px" }}>
        <Box id="about">
          <Intro />
        </Box>
        <Box id="skills" sx={{ padding: 4 }}>
          <Skills />
        </Box>
        <Box id="experience" sx={{ padding: 4 }}>
          <Experience />
        </Box>
        <Box id="projects" sx={{ padding: 2 }}>
          <Projects />
        </Box>
        <Box id="education" sx={{ padding: 2 }}>
          <About />
        </Box>
        <Box id="contact" sx={{ padding: 4 }}>
          <Contact />
        </Box>
      </Box>
    </div>
  );
};

export default Dashboard;
